import { execution } from '@dynatrace-sdk/automation-utils';
import { entitiesClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  const tags = typeof input.tags === 'string' ? JSON.parse(input.tags) : input.tags;
  const action = input.action.toUpperCase();

  try {
    let tagUpdates = [];

    if (action === 'ADD' || action === 'REPLACE') {
      tagUpdates = tags;
    } else if (action === 'REMOVE') {
      tagUpdates = tags.map(t => ({ key: t.key, value: null }));
    }

    const response = await entitiesClient.updateEntityTags({
      entityId: input.entityId,
      body: { tags: tagUpdates }
    });

    console.log(`Updated tags for ${input.entityId}`);

    return {
      entityId: input.entityId,
      action: action,
      appliedTags: tagUpdates,
      success: true
    };
  } catch (error) {
    console.error('Error managing tags:', error);
    throw new Error(`Failed to manage tags: ${error}`);
  }
}
